from string_utils.generation import roman_range

def test_roman_range_negative_step_edge_case():
    """
    Test with start greater than stop and a negative step which
    should raise an OverflowError in the baseline but might not in the mutant.
    """
    try:
        list(roman_range(stop=1, start=10, step=-1))
        assert False, "Expected OverflowError was not raised"
    except OverflowError:
        print("OverflowError raised correctly in baseline.")
    except Exception as e:
        assert False, f"Unexpected exception raised: {e}"

